    and jf.ghlb_dm = #{req.ghlbDm}
    and jf.xtlb_dm = #{req.xtlbDm}
    and jf.hkpch = #{req.hkpch}
    and jf.jcghzh = #{req.jcghzh}
    and jf.jcghhh = #{req.jcghhh}
    and jf.cbjthbj = #{req.cbjthbj}

        and jf.jsbj in

            #{item}



        and hj.hjfl6_dm in

            #{item}



        and hj.hjfl4_dm in

            #{item}



        and hj.hjfl10_dm in

            #{item}


    and jf.rkrq between #{req.beginRkrq} and #{req.endRkrq}
    and jf.jsrq between #{req.beginJsrq} and #{req.endJsrq}
    and jf.cbjthrq between #{req.beginCbjthrq} and #{req.endCbjthrq}

order by jf.ghjf_id desc

select * from gh_jf

    and dept_id = #{req.deptId}
    and djxh = #{req.djxh}
    and nsrmc like concat('%', #{req.nsrmc}, '%')
    and shxydm = #{req.shxydm}
    and zspm_dm = #{req.zspmDm}

order by ghjf_id desc

select t.dwdm as sjdm, t.dept_id as xjdm, t.dept_id as deptId, count(t.djxh) as bs, count(distinct t.djxh) as hs, sum(t.gzze) as gzze, sum(t.ybtse) as ybtse, round(sum(t.hyghje+t.xjghje+t.sjghje+t.szghje+t.qgghje+t.swjgje+t.sdsje+t.sdghje),2) as sjje, round(sum(t.hyghje+t.xjghje+t.sjghje+t.szghje+t.qgghje+t.sdghje),2) as xeje, sum(t.jcghje) as jcghje, sum(t.hyghje) as hyghje, sum(t.sdghje) as sdghje, sum(t.cbjje) as cbjje, sum(t.xjghje) as xjghje, sum(t.sjghje) as sjghje, sum(t.szghje) as szghje, sum(t.qgghje) as qgghje, sum(t.swjgje) as swjgje, sum(t.sdsje) as sdsje from szjfcx t
